public class JumpDemo {
    public static void main(String[] args) {
        // break
        for (int i = 1; i <= 5; i++) {
            if (i == 3) break;
            System.out.print(i + " ");
        }
        System.out.println("(break at 3)");

        // continue
        for (int i = 1; i <= 5; i++) {
            if (i == 3) continue;
            System.out.print(i + " ");
        }
        System.out.println("(skipped 3)");

        // return
        System.out.println("Before return");
        return; // exits method
        // System.out.println("After return"); // unreachable
    }
}

