    // Default constructor
    Employee() {
        this.name = "Unknown";
        this.id = 0;
        this.salary = 0.0;
    }

    // Parameterized constructor
    Employee(String name) {
        this.name = name;
        this.id = 0;
        this.salary = 0.0;
    }

    Employee(String name, int id) {
        this.name = name;
        this.id = id;
        this.salary = 0.0;
    }

    Employee(String name, int id, double salary) {
        this.name = name;
        this.id = id;
        this.salary = salary;
    }

