// LSP Violation Example
class Rectangle {
    protected int width;
    protected int height;

    void setWidth(int width) { this.width = width; }
    void setHeight(int height) { this.height = height; }
    int getArea() { return width * height; }
}

// Violates LSP - Square changes behavior
class Square extends Rectangle {
    @Override
    void setWidth(int width) {
        super.setWidth(width);
        super.setHeight(width);
    }

    @Override
    void setHeight(int height) {
        super.setHeight(height);
        super.setWidth(height);
    }
}

public class LSPDemo {
    public static void main(String[] args) {
        Rectangle r = new Square();
        r.setWidth(5);
        r.setHeight(10);
        // If r was Rectangle, area = 50
        // But with Square, area = 100 (violates LSP)
        System.out.println("Area: " + r.getArea());
    }
}

public class ExceptionHierarchyDemo {
    public static void main(String[] args) {
        try {
            // ArithmeticException (unchecked)
            int result = 10 / 0;
        } catch (ArithmeticException e) {
            System.out.println("ArithmeticException caught");
        }

        try {
            // NullPointerException (unchecked)
            String str = null;
            System.out.println(str.length());
        } catch (NullPointerException e) {
            System.out.println("NullPointerException caught");
        }

        try {
            // ArrayIndexOutOfBoundsException (unchecked)
            int[] arr = new int[5];
            System.out.println(arr[10]);
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("ArrayIndexOutOfBoundsException caught");
        }
    }
}

import java.io.*;

public class CheckedUncheckedDemo {
    public static void main(String[] args) {
        // Unchecked exception - not required to handle
        int result = 10 / 0;  // ArithmeticException

        // Checked exception - must handle
        try {
            FileReader fr = new FileReader("file.txt");  // IOException
        } catch (FileNotFoundException e) {
            System.out.println("File not found");
        }

        // Unchecked exception - common programming errors
        String str = null;
        str.length();  // NullPointerException

        int[] arr = new int[5];
        arr[10] = 100;  // ArrayIndexOutOfBoundsException
    }
}

public class TryCatchFinally {
    public static void main(String[] args) {
        System.out.println("Program start");

        try {
            System.out.println("Entering try block");
            int[] numbers = {10, 20, 30};
            System.out.println("Accessing index 5: " + numbers[5]);
            System.out.println("This line won't execute");
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("Caught: " + e.getMessage());
        } catch (ArithmeticException e) {
            System.out.println("Caught: " + e.getMessage());
        } finally {
            System.out.println("Finally block always executes");
        }

        System.out.println("Program continues");

        // Example with finally returning value
        System.out.println("\nResult: " + testFinally());
    }

    static int testFinally() {
        try {
            return 10;
        } catch (Exception e) {
            return 20;
        } finally {
            System.out.println("Finally in testFinally");
        }
    }
}

