            try {
                System.out.println("Processing: " + input);

                // Multiple exceptions possible
                int num = Integer.parseInt(input);
                int result = 100 / num;
                System.out.println("Result: " + result);

                // Access array
                int[] arr = new int[5];
                arr[10] = result;

            } catch (NumberFormatException e) {
                System.out.println("NumberFormatException: " + input);
            } catch (ArithmeticException e) {
                System.out.println("ArithmeticException: " + input);
            } catch (Exception e) {
                System.out.println("Generic Exception: " + e.getMessage());
            }
        }

        System.out.println("\n=== Multi-catch Example ===");
        try {
            // Code that may throw multiple exceptions
            String str = null;
            str.length();  // NullPointerException

            int[] arr = new int[3];
            arr[5] = 10;  // ArrayIndexOutOfBoundsException

        } catch (NullPointerException | ArrayIndexOutOfBoundsException e) {
            System.out.println("Caught: " + e.getClass().getSimpleName());
        }
    }
}

public class NestedTryDemo {
    public static void main(String[] args) {
        System.out.println("Outer try block");

        try {
            System.out.println("Outer try - before inner try");

            // Inner try block 1
            try {
                System.out.println("Inner try 1");
                int[] arr = new int[3];
                arr[5] = 10;  // ArrayIndexOutOfBoundsException
                System.out.println("This line won't execute");
            } catch (ArrayIndexOutOfBoundsException e) {
                System.out.println("Inner catch 1: " + e.getMessage());
            }

            // Inner try block 2
            try {
                System.out.println("\nInner try 2");
                int result = 10 / 0;  // ArithmeticException
                System.out.println("This line won't execute");
            } catch (NumberFormatException e) {
                System.out.println("Inner catch 2: " + e.getMessage());
            }

            // Inner try block 3 - uncaught exception
            try {
                System.out.println("\nInner try 3 - uncaught exception");
                String str = null;
                str.length();  // NullPointerException - not caught inner
                System.out.println("This line won't execute");
            } catch (ArithmeticException e) {
                System.out.println("Inner catch 3: " + e.getMessage());
            }

            System.out.println("Outer try - after inner try");
        } catch (NullPointerException e) {
            System.out.println("Outer catch: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("Outer catch: " + e.getMessage());
        }

        System.out.println("\nProgram continues after outer try");

        // Nested try with multiple levels
        try {
            try {
                try {
                    int[] data = new int[2];
                    data[3] = 5;
                } catch (ArithmeticException e) {
                    System.out.println("Deepest catch");
                }
            } catch (ArrayIndexOutOfBoundsException e) {
                System.out.println("Middle catch");
            }
        } catch (Exception e) {
            System.out.println("Outer catch");
        }
    }
}

