        System.out.println("intBox class: " + intBox.getClass().getName());
        System.out.println("Same class? " + stringBox.getClass().equals(intBox.getClass()));

        // Bridge methods example
        Parent p = new Child();
        p.print("Hello");  // Calls Child's print

