import java.util.*;

public class IteratorDemo {
    public static void main(String[] args) {
        // Basic Iterator
        System.out.println("=== Basic Iterator ===");
        List<String> fruits = new ArrayList<>();
        fruits.add("Apple");
        fruits.add("Banana");
        fruits.add("Orange");
        fruits.add("Grapes");

        Iterator<String> it = fruits.iterator();
        System.out.print("Iterating: ");
        while (it.hasNext()) {
            System.out.print(it.next() + " ");
        }
        System.out.println();

        // Iterator with removal
        System.out.println("\n=== Iterator with Removal ===");
        List<Integer> numbers = new ArrayList<>();
        for (int i = 1; i <= 10; i++) numbers.add(i);
        System.out.println("Original: " + numbers);

        Iterator<Integer> numIt = numbers.iterator();
        while (numIt.hasNext()) {
            int num = numIt.next();
            if (num % 2 == 0) {
                numIt.remove();  // Remove even numbers
            }
        }
        System.out.println("After removing even: " + numbers);

        // ListIterator
        System.out.println("\n=== ListIterator (Bidirectional) ===");
        List<String> names = new ArrayList<>();
        names.add("Alice");
        names.add("Bob");
        names.add("Charlie");

        ListIterator<String> listIt = names.listIterator();
        System.out.print("Forward: ");
        while (listIt.hasNext()) {
            System.out.print(listIt.next() + " ");
        }
        System.out.println();

        System.out.print("Backward: ");
        while (listIt.hasPrevious()) {
            System.out.print(listIt.previous() + " ");
        }
        System.out.println();

        // Enhanced for loop (uses Iterator internally)
        System.out.println("\n=== Enhanced for loop ===");
        for (String name : names) {
            System.out.print(name + " ");
        }
        System.out.println();

        // Custom Iterable implementation
        System.out.println("\n=== Custom Iterable ===");
        MyCollection myCol = new MyCollection();
        for (String item : myCol) {
            System.out.print(item + " ");
        }
        System.out.println();
    }
}

class MyCollection implements Iterable<String> {
    private String[] data = {"A", "B", "C", "D"};

    @Override
    public Iterator<String> iterator() {
        return new Iterator<String>() {
            int index = 0;
            @Override
            public boolean hasNext() {
                return index < data.length;
            }
            @Override
            public String next() {
                return data[index++];
            }
        };
    }
}

