class PriorityThread extends Thread {
    static int lowCount = 0;
    static int normalCount = 0;
    static int highCount = 0;

    PriorityThread(String name) {
        super(name);
    }

    @Override
    public void run() {
        for (int i = 0; i < 1000000; i++) {
            // Increment appropriate counter
            if (getPriority() == Thread.MIN_PRIORITY) {
                lowCount++;
            } else if (getPriority() == Thread.MAX_PRIORITY) {
                highCount++;
            } else {
                normalCount++;
            }
        }
        System.out.println(getName() + " priority thread completed");
    }
}

class TicketCounter {
    private int availableSeats = 10;

    // Synchronized method
    public synchronized boolean bookTicket(String threadName, int seats) {
        System.out.println(threadName + " attempting to book " + seats + " seats");

        if (seats <= availableSeats) {
            availableSeats -= seats;
            System.out.println(threadName + " booked " + seats + " seats. Remaining: " + availableSeats);
            return true;
        } else {
            System.out.println(threadName + " failed. Only " + availableSeats + " seats available");
            return false;
        }
    }

    // Synchronized block example
    public void processBooking(String threadName, int seats) {
        // Other code
        synchronized(this) {
            if (seats <= availableSeats) {
                availableSeats -= seats;
                System.out.println(threadName + " (block) booked " + seats + " seats. Remaining: " + availableSeats);
            }
        }
    }
}

