        System.out.println("\n=== Without Synchronization ===");
        UnsafeCounter unsafe = new UnsafeCounter();
        Thread[] threads = new Thread[10];

        for (int i = 0; i < 10; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 1000; j++) {
                    unsafe.increment();
                }
            });
