        }

        System.out.println("Safe counter (should be 10000): " + safe.getCount());
    }
}

class UnsafeCounter {
    private int count = 0;

    void increment() {
        count++;
    }

    int getCount() {
        return count;
    }
}

class SafeCounter {
    private int count = 0;

    synchronized void increment() {
        count++;
    }

    int getCount() {
        return count;
    }
}

// Example of race condition
public class RaceConditionDemo {
    public static void main(String[] args) throws InterruptedException {
        // Race condition example
        System.out.println("=== Race Condition Example ===");
        Counter counter = new Counter();
        Thread[] threads = new Thread[5];

        // Create threads that increment counter
        for (int i = 0; i < 5; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 10000; j++) {
                    counter.increment();
                }
            });
            threads[i].start();
        }

        // Wait for all threads
        for (Thread t : threads) {
            t.join();
        }

        System.out.println("Expected: 50000, Actual: " + counter.getValue());

        // Fixed version with synchronization
        System.out.println("\n=== Fixed with Synchronization ===");
        SafeCounter safeCounter = new SafeCounter();
        Thread[] safeThreads = new Thread[5];

        for (int i = 0; i < 5; i++) {
            safeThreads[i] = new Thread(() -> {
                for (int j = 0; j < 10000; j++) {
                    safeCounter.increment();
                }
            });
            safeThreads[i].start();
        }

        for (Thread t : safeThreads) {
            t.join();
        }

        System.out.println("Expected: 50000, Actual: " + safeCounter.getValue());
    }
}

class Counter {
    private int value = 0;

    void increment() {
        // Non-atomic operation: read-modify-write
        int temp = value;  // Read
        temp = temp + 1;   // Modify
        value = temp;      // Write
    }

    int getValue() {
        return value;
    }
}

class SafeCounter {
    private int value = 0;

    synchronized void increment() {
        value++;
    }

    synchronized int getValue() {
        return value;
    }
}

