import java.io.*;

public class ByteStreamDemo {
    public static void main(String[] args) {
        System.out.println("=== Byte Streams Demonstration ===\n");

        // Write bytes to file
        try (FileOutputStream fos = new FileOutputStream("data.bin")) {
            byte[] data = {10, 20, 30, 40, 50};
            fos.write(data);
            System.out.println("Data written: " + java.util.Arrays.toString(data));
        } catch (IOException e) {
            System.err.println("Error writing: " + e.getMessage());
        }

        // Read bytes from file
        try (FileInputStream fis = new FileInputStream("data.bin")) {
            System.out.println("\nReading bytes:");
            int b;
            while ((b = fis.read()) != -1) {
                System.out.print(b + " ");
            }
            System.out.println();
        } catch (IOException e) {
            System.err.println("Error reading: " + e.getMessage());
        }

        // Copy file
        try {
            copyFile("data.bin", "data_copy.bin");
            System.out.println("\nFile copied successfully");
        } catch (IOException e) {
            System.err.println("Error copying: " + e.getMessage());
        }

        // Write with DataOutputStream
        System.out.println("\n=== DataOutputStream ===");
        try (DataOutputStream dos = new DataOutputStream(
                new FileOutputStream("data.dat"))) {
            dos.writeInt(100);
            dos.writeDouble(3.14);
            dos.writeUTF("Hello Java");
            System.out.println("Primitive data written");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Read with DataInputStream
        System.out.println("\n=== DataInputStream ===");
        try (DataInputStream dis = new DataInputStream(
                new FileInputStream("data.dat"))) {
            int i = dis.readInt();
            double d = dis.readDouble();
            String s = dis.readUTF();
            System.out.println("Read: " + i + ", " + d + ", " + s);
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static void copyFile(String source, String dest) throws IOException {
        try (FileInputStream fis = new FileInputStream(source);
             FileOutputStream fos = new FileOutputStream(dest)) {
            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = fis.read(buffer)) != -1) {
                fos.write(buffer, 0, bytesRead);
            }
        }
    }
}

