            System.out.println("You are " + age + " years old");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Copy file with buffered streams
        System.out.println("\n=== Copying File with Buffered Streams ===");
        try (BufferedReader reader = new BufferedReader(
                new FileReader("buffered.txt"));
             BufferedWriter writer = new BufferedWriter(
                new FileWriter("buffered_copy.txt"))) {
            String line;
            while ((line = reader.readLine()) != null) {
                writer.write(line);
                writer.newLine();
            }
            System.out.println("File copied successfully");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Mark and reset
        System.out.println("\n=== Mark and Reset ===");
        try (BufferedReader reader = new BufferedReader(
                new FileReader("buffered.txt"))) {
            // Mark position
            reader.mark(100);
            System.out.println("Line 1: " + reader.readLine());
            System.out.println("Line 2: " + reader.readLine());
            reader.reset();  // Go back to marked position
            System.out.println("After reset - Line 1: " + reader.readLine());
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
