import java.io.*;

public class RandomAccessFileDemo {
    public static void main(String[] args) throws IOException {
        System.out.println("=== RandomAccessFile Demonstration ===\n");

        String filename = "random.dat";

        // Write data
        try (RandomAccessFile raf = new RandomAccessFile(filename, "rw")) {
            System.out.println("Writing data...");

            // Write records
            writeRecord(raf, 1, "Alice", 25, 50000.0);
            writeRecord(raf, 2, "Bob", 30, 60000.0);
            writeRecord(raf, 3, "Charlie", 35, 70000.0);
            writeRecord(raf, 4, "David", 40, 80000.0);

            System.out.println("Data written successfully");
        }

        // Read specific record
        System.out.println("\n=== Reading Specific Record ===");
        try (RandomAccessFile raf = new RandomAccessFile(filename, "r")) {
            // Read record 2
            System.out.println("Reading record 2:");
            readRecord(raf, 2);

            // Read record 4
            System.out.println("\nReading record 4:");
            readRecord(raf, 4);
        }

        // Update record
        System.out.println("\n=== Updating Record ===");
        try (RandomAccessFile raf = new RandomAccessFile(filename, "rw")) {
            System.out.println("Updating record 3...");

            // Move to record 3 position
            raf.seek(3 * 64);  // 64 bytes per record

            // Update data
            raf.writeInt(3);  // ID
            raf.writeUTF("Charlie Updated");  // Name
            raf.writeInt(36);  // Age
            raf.writeDouble(72000.0);  // Salary

            System.out.println("Record 3 updated");
        }

        // Read all records
        System.out.println("\n=== Reading All Records ===");
        try (RandomAccessFile raf = new RandomAccessFile(filename, "r")) {
            System.out.println("All records:");
            while (raf.getFilePointer() < raf.length()) {
                readRecordAtPosition(raf);
            }
        }

        // File pointer operations
        System.out.println("\n=== File Pointer Operations ===");
        try (RandomAccessFile raf = new RandomAccessFile(filename, "r")) {
            System.out.println("Initial position: " + raf.getFilePointer());
            raf.seek(100);
            System.out.println("After seek(100): " + raf.getFilePointer());
            raf.skipBytes(50);
            System.out.println("After skipBytes(50): " + raf.getFilePointer());
            System.out.println("File length: " + raf.length());
        }

        // Clean up
        new File(filename).delete();
    }

    static void writeRecord(RandomAccessFile raf, int id, String name, 
                           int age, double salary) throws IOException {
        raf.writeInt(id);
        raf.writeUTF(name);
        raf.writeInt(age);
        raf.writeDouble(salary);
    }

    static void readRecord(RandomAccessFile raf, int id) throws IOException {
        // Move to record position
        raf.seek(id * 64);  // Each record takes 64 bytes
        readRecordAtPosition(raf);
    }

    static void readRecordAtPosition(RandomAccessFile raf) throws IOException {
        int id = raf.readInt();
        String name = raf.readUTF();
        int age = raf.readInt();
        double salary = raf.readDouble();
        System.out.printf("ID: %d, Name: %s, Age: %d, Salary: $%.2f%n", 
                         id, name, age, salary);
    }
}

import java.io.*;
import java.util.*;

// Serializable class
class Employee implements Serializable {
    private static final long serialVersionUID = 1L;

    private int id;
    private String name;
    private double salary;
    private transient String password;  // Not serialized
    private Date hireDate;

    public Employee(int id, String name, double salary, String password) {
        this.id = id;
        this.name = name;
        this.salary = salary;
        this.password = password;
        this.hireDate = new Date();
    }

    @Override
    public String toString() {
        return String.format("ID: %d, Name: %s, Salary: $%.2f, Password: %s, Hired: %s",
                           id, name, salary, password, hireDate);
    }
}

public class SerializationDemo {
    public static void main(String[] args) {
        System.out.println("=== Serialization Demonstration ===\n");

        String filename = "employees.ser";

        // Create objects to serialize
        Employee[] employees = {
            new Employee(1, "Alice", 50000, "pass123"),
            new Employee(2, "Bob", 60000, "secret456"),
            new Employee(3, "Charlie", 70000, "hidden789")
        };

        // Serialize
        System.out.println("=== Serializing Objects ===");
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new FileOutputStream(filename))) {
            // Write array
            oos.writeObject(employees);
            System.out.println("Objects serialized successfully");
        } catch (IOException e) {
            System.err.println("Serialization error: " + e.getMessage());
        }

        // Deserialize
        System.out.println("\n=== Deserializing Objects ===");
        try (ObjectInputStream ois = new ObjectInputStream(
                new FileInputStream(filename))) {
            Employee[] deserialized = (Employee[]) ois.readObject();
            System.out.println("Objects deserialized successfully\n");
            for (Employee emp : deserialized) {
                System.out.println(emp);
            }
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Deserialization error: " + e.getMessage());
        }

        // Serialize with ArrayList
        System.out.println("\n=== Serializing ArrayList ===");
        List<String> list = Arrays.asList("Java", "Python", "C++");
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new FileOutputStream("list.ser"))) {
            oos.writeObject(list);
            System.out.println("ArrayList serialized");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Deserialize ArrayList
        System.out.println("\n=== Deserializing ArrayList ===");
        try (ObjectInputStream ois = new ObjectInputStream(
                new FileInputStream("list.ser"))) {
            List<String> deserializedList = (List<String>) ois.readObject();
            System.out.println("Deserialized list: " + deserializedList);
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Error: " + e.getMessage());
        }

        // Clean up
        new File(filename).delete();
        new File("list.ser").delete();

        // Demonstrate transient field
        System.out.println("\n=== Transient Field ===");
        System.out.println("Note: Password (transient) is not serialized and appears as 'null'");
    }
}

import java.nio.file.*;
import java.nio.file.attribute.*;
import java.io.*;
import java.util.*;

public class NIO2Demo {
    public static void main(String[] args) throws IOException {
        System.out.println("=== NIO.2 API Demonstration ===\n");

        // Create Path
        Path path = Paths.get("nio_test.txt");
        System.out.println("Path: " + path);
        System.out.println("Absolute path: " + path.toAbsolutePath());
        System.out.println("File name: " + path.getFileName());
        System.out.println("Parent: " + path.getParent());

        // Create and write file
        System.out.println("\n=== Writing File ===");
        List<String> lines = Arrays.asList("Line 1", "Line 2", "Line 3");
        Files.write(path, lines);
        System.out.println("File written: " + Files.exists(path));

        // Read file
        System.out.println("\n=== Reading File ===");
        List<String> readLines = Files.readAllLines(path);
        System.out.println("File content:");
        for (String line : readLines) {
            System.out.println("  " + line);
        }

        // File operations
        System.out.println("\n=== File Operations ===");
        System.out.println("File size: " + Files.size(path) + " bytes");
        System.out.println("Is directory: " + Files.isDirectory(path));
        System.out.println("Is regular file: " + Files.isRegularFile(path));
        System.out.println("Is readable: " + Files.isReadable(path));
        System.out.println("Is writable: " + Files.isWritable(path));

        // Copy file
        System.out.println("\n=== Copying File ===");
        Path copyPath = Paths.get("nio_copy.txt");
        Files.copy(path, copyPath, StandardCopyOption.REPLACE_EXISTING);
        System.out.println("File copied: " + Files.exists(copyPath));

        // Move file
        System.out.println("\n=== Moving File ===");
        Path movePath = Paths.get("nio_moved.txt");
        Files.move(copyPath, movePath, StandardCopyOption.REPLACE_EXISTING);
        System.out.println("File moved: " + Files.exists(movePath));
        System.out.println("Original exists: " + Files.exists(copyPath));

        // File attributes
        System.out.println("\n=== File Attributes ===");
        BasicFileAttributes attrs = Files.readAttributes(path, BasicFileAttributes.class);
        System.out.println("Creation time: " + attrs.creationTime());
        System.out.println("Last modified: " + attrs.lastModifiedTime());
        System.out.println("Size: " + attrs.size() + " bytes");
        System.out.println("Is directory: " + attrs.isDirectory());
        System.out.println("Is regular file: " + attrs.isRegularFile());

        // Directory operations
        System.out.println("\n=== Directory Operations ===");
        Path dirPath = Paths.get("nio_dir");
        if (!Files.exists(dirPath)) {
            Files.createDirectory(dirPath);
            System.out.println("Directory created: " + dirPath);
        }

        // Create subdirectories
        Path subDirPath = Paths.get("nio_dir/sub/sub2");
        Files.createDirectories(subDirPath);
        System.out.println("Subdirectories created: " + subDirPath);

        // List directory
        System.out.println("\n=== Listing Directory ===");
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(Paths.get("."))) {
            System.out.println("Current directory contents:");
            for (Path p : stream) {
                System.out.println("  " + p.getFileName());
            }
        }

        // Walk file tree
        System.out.println("\n=== Walking File Tree ===");
        Files.walk(Paths.get("."), 2)
             .filter(p -> !p.toString().contains(".git"))
             .forEach(p -> System.out.println("  " + p));

        // Clean up
        Files.deleteIfExists(path);
        Files.deleteIfExists(movePath);
        Files.walk(dirPath)
             .sorted(Comparator.reverseOrder())
             .forEach(p -> {
                 try {
                     Files.deleteIfExists(p);
                 } catch (IOException e) {
                     e.printStackTrace();
                 }
             });
        System.out.println("\nCleanup completed");
    }
}

import java.io.*;

public class ConsoleDemo {
    public static void main(String[] args) {
        System.out.println("=== Console Class Demonstration ===\n");

        // Get console
        Console console = System.console();

        if (console == null) {
            System.err.println("No console available! Run from command line.");
            System.err.println("Alternatively, use Scanner for input.");
            return;
        }

        // Read line
        String name = console.readLine("Enter your name: ");

        // Read password (hidden)
        char[] password = console.readPassword("Enter password: ");
        String passStr = new String(password);

        // Read with formatting
        int age = Integer.parseInt(console.readLine("Enter your age: "));

        // Formatted output
        console.printf("\n=== User Information ===%n");
        console.printf("Name: %s%n", name);
        console.printf("Age: %d%n", age);
        console.printf("Password length: %d%n", passStr.length());
        console.printf("\nPassword characters: ");
        for (char c : password) {
            console.printf("%c ", c);
        }
        console.printf("%n");

        // Using writer
        PrintWriter writer = console.writer();
        writer.println("\n=== Using Writer ===");
        writer.println("This is written using PrintWriter");
        writer.flush();

        // Reading with reader
        try {
            Reader reader = console.reader();
            System.out.println("\n=== Using Reader ===");
            System.out.print("Enter additional text: ");
            char[] buffer = new char[100];
            int charsRead = reader.read(buffer);
            if (charsRead > 0) {
                String additional = new String(buffer, 0, charsRead);
                System.out.println("You entered: " + additional);
            }
        } catch (IOException e) {
            System.err.println("Error reading: " + e.getMessage());
        }

        // Formatting examples
        console.printf("\n=== Formatting Examples ===%n");
        console.printf("Integer: %d%n", 100);
        console.printf("Float: %.2f%n", 3.14159);
        console.printf("String: %s%n", "Hello");
        console.printf("Date: %tD%n", System.currentTimeMillis());
        console.printf("Time: %tT%n", System.currentTimeMillis());

        // Clearing password
        java.util.Arrays.fill(password, ' ');

        System.out.println("\nPassword cleared from memory");
    }
}
